    #[must_use]
    pub const fn read_only(mut self, read_only: bool) -> Self {
        self.read_only = read_only;
        self
    }

    /// Sets [`disabled_items`](Self::disabled_items).
    #[must_use]
    pub fn disabled_items(mut self, disabled_items: BTreeSet<Key>) -> Self {
