            disabled_items: key_set(&["strike"]),
            ..old.clone()
        };

        assert_eq!(
            <Machine as ars_core::Machine>::on_props_changed(&old, &new),
            vec![Event::SetValue(Some(key_set(&["italic"]))), Event::SetProps],
        );

