            (_, Event::Focus { item, is_keyboard }) => {
                let item = item.clone();
                let is_keyboard = *is_keyboard;
                Some(TransitionPlan::to(State::Focused { item: item.clone() })
                    .apply(move |ctx| {
                        ctx.focused_item = Some(item);
                        ctx.focus_visible = is_keyboard;
                    }))
            }

